function parse(raw){try{return JSON.parse(String(raw).replace(/```json/gi,'').replace(/```/g,'').trim());}catch(e){const m=String(raw).match(/\{[\s\S]*\}/);if(m){try{return JSON.parse(m[0]);}catch(e2){}}return null;}}
const t = $('Execute Workflow Trigger').first().json.data;
// Monitor adalah AI Agent -> outputnya { output: "<string JSON>" }.
// Wajib di-parse; membaca point_satisfied langsung selalu undefined.
const rawMon = $input.first().json;
const mon = parse(rawMon.output ?? rawMon.text ?? '') || rawMon;
const satisfied = mon.point_satisfied === true;
const K = Number(t.total_points) || (t.plan ? t.plan.length : 0);
let idx = Number(t.current_point_index) || 1;
let qc = Number(t.point_qcount) || 1;
const CAP = 5;
let done = false;
if (satisfied || qc >= CAP) { idx = idx + 1; qc = 1; if (idx > K) done = true; }
else { qc = qc + 1; }
const target = (!done && t.plan && t.plan[idx-1]) ? t.plan[idx-1] : null;
return [{ json: { done, current_point_index: idx, point_qcount: qc,
  point_satisfied: satisfied, satisfied_reason: mon.reason || '',
  monitor_gap: mon.gap || '',
  total_points: K, target_point: target } }];

