function parse(raw){try{return JSON.parse(String(raw).replace(/```json/gi,'').replace(/```/g,'').trim());}catch(e){const m=String(raw).match(/\{[\s\S]*\}/);if(m){try{return JSON.parse(m[0]);}catch(e2){}}return null;}}

let p = parse($input.first().json.output ?? $input.first().json.text ?? '');
if(!p) return [{ json: { error: '⚠️ Format penilaian tidak valid, coba lagi.' } }];

// Skor dihitung SISTEM dari rubrik, bukan ditebak LLM.
const dims = Array.isArray(p.dimensions) ? p.dimensions : [];
const vals = dims.map(d => Number(d.score))
  .filter(n => Number.isFinite(n) && n >= 0 && n <= 10);
const score = vals.length
  ? Math.round((vals.reduce((a,b) => a + b, 0) / vals.length) * 10)
  : null;
p.score = score;
p.verdict = (score !== null && score >= 70)
  ? 'Bisa Diterima' : 'Tidak Bisa Diterima';

// Confidence dari CAKUPAN wawancara (bukan dari skor).
const plan = ($('Execute Workflow Trigger').first().json.data.plan) || [];
const cov = p.coverage || {};
const explored = Array.isArray(cov.explored) ? cov.explored.length : 0;
const notExp = Array.isArray(cov.not_explored) ? cov.not_explored.length : 0;
const total = plan.length || (explored + notExp) || 1;
const ratio = Math.max(0, Math.min(explored / total, 1));
p.coverage = Object.assign({}, cov, {
  explored_count: explored, total_points: total,
  ratio_pct: Math.round(ratio * 100)
});
// Cakupan plan saja tidak cukup: banyak skill CV/lowongan yang tak diuji
// harus menurunkan keyakinan, supaya penilaian tidak sirkular.
const untested = Array.isArray(cov.untested_areas) ? cov.untested_areas : [];
let conf = ratio >= 0.8 ? 'high' : (ratio >= 0.5 ? 'medium' : 'low');
if (untested.length >= 3 && conf === 'high') conf = 'medium';
if (untested.length >= 5) conf = 'low';
p.confidence = conf;
p.coverage.untested_areas = untested;

p.dimensions = dims;
p.reasons = p.reasons || [];
p.strengths = p.strengths || [];
p.improvements = p.improvements || [];
p.self_awareness = p.self_awareness || [];
p.per_question = p.per_question || [];
return [{ json: p }];
